NoneHermite-interpolation through Newton dd






%
% hermite polinomial computation
%
% expects:
%    data: a cell array of arrays: {[t1,f1,f1',...],...,[tn,fn,fn']}
% 
% returns:
%    H: the coefficients, in decreasing order
%    t: the support points in the appropriate order
%
% side effect:
%    displays the computed table
%
function [H,t] = hermite_interpolation(data)
  m = cellfun(@length,data)-1; % individual numbers of conditions
  n = length(m); % number of basis points
  M = sum(m); % total number of conditions (deg(H)&lt;=M-1)
  lab = repelem((1:n)',m); % labels for identify base points
  t_orig = zeros(n,1); % original t's
  f_orig = zeros(n,1); % original f's
  for k=1:n
    % get the individual values
    t_orig(k)=data{k}(1);
    f_orig(k)=data{k}(2);
  end
  t = repelem(t_orig, m); % nodes w/ multiplicity
  f = repelem(f_orig, m); % values w/ multiplicity
  table = {f}; % the initial table (the 0-th column is given)
  for j = 1:M-1
    table{j+1}=zeros(M-j,1); % j+1 -&gt; one based indexing
    for i=1:M-j
      if lab(i)==lab(i+j) % div by zero
        table{j+1}(i)=data{lab(i)}(j+2)/factorial(j); % j+2 -&gt; t,f is the first 2
      else
        table{j+1}(i)=(table{j}(i)-table{j}(i+1))/(t(i)-t(i+j));
      end
    end
  end
  H=zeros(M,1);
  for k=1:M
    H(k)=table{k}(1); % reading from the upper edge
  end
  % display the table
  disp(t');
  for k=1:M
    disp(table{k}');
  end


  % reverse them to get decreasing order for degrees
  H=H(end:-1:1);
  t=t(end:-1:1);
end










