we have mod(2) arithmetic: xor (for logical/boolean values)


% lights out puzzle by linear algebra
% one among several different aproaches
% it can be shortened by using specific matlab features (true,false)
% the sizes a wired in constants
% columnwise flattening used! matrix -&gt; matrix(:)
% in a mod(2) system the elimination is a simple xor() operation:
% aj=aj-1*ai is the only possible elimination operation and -1 is 1 (mod(2)).

clc; clear;

% initial state
% these are puzzles from the applet in the link
%
% puzzle 1
% S=zeros(5,5); 
% S(3,:)=[1,0,1,0,1]; 
% S=logical(S);
%
% puzzle 2
